const SUPABASE_URL='https://mohbirhrtbgilwtuxdcu.supabase.co';
const SUPABASE_ANON_KEY='sb_publishable_TpSVjpmseRSdp6JnTcm4nw_CSvh_9Ko';

let sb=null,_sbLoading=null;
function supabaseReady(){return !!(SUPABASE_URL&&SUPABASE_ANON_KEY);}
function ensureSupabase(){
  if(sb)return Promise.resolve(sb);
  if(!supabaseReady())return Promise.reject('Falta configurar SUPABASE_URL y SUPABASE_ANON_KEY');
  if(_sbLoading)return _sbLoading;
  _sbLoading=new Promise((res,rej)=>{
    const init=()=>{try{sb=window.supabase.createClient(SUPABASE_URL,SUPABASE_ANON_KEY);res(sb);}catch(e){rej(e);}};
    if(window.supabase)return init();
    const s=document.createElement('script');
    s.src='https://cdn.jsdelivr.net/npm/@supabase/supabase-js@2';
    s.onload=init; s.onerror=()=>rej('No se pudo cargar la librería de Supabase');
    document.head.appendChild(s);
  });
  return _sbLoading;
}
/* Ejemplo de login con Supabase (equivalente a tu snippet) */
async function supaLogin(email,password){
  try{
    const c=await ensureSupabase();
    const {data,error}=await c.auth.signInWithPassword({email,password});
    if(error){toast('Error: '+error.message);return null;}
    return data.user;
  }catch(e){toast(typeof e==='string'?e:'Error de conexión con Supabase');return null;}
}
/* ---- Sincronización de mercados (ubicación de tiendas) con Supabase ----
   Tabla 'mercados' (ver SQL en el README). Si no existe o falla, se usa solo memoria/local. */
async function saveMarketCloud(v){
  if(!supabaseReady()||!v||!v.location)return;
  try{
    const c=await ensureSupabase();
    await c.from('mercados').upsert({
      vendor_id:v.id, company:v.company, market:v.market||'',
      lat:v.location.lat, lng:v.location.lng, updated_at:new Date().toISOString()
    },{onConflict:'vendor_id'});
  }catch(e){ /* silencioso: cae a memoria/local */ }
}
async function loadMarketsCloud(){
  if(!supabaseReady())return;
  try{
    const c=await ensureSupabase();
    const {data,error}=await c.from('mercados').select('vendor_id,company,market,lat,lng');
    if(error||!data)return;
    let changed=false;
    data.forEach(row=>{
      const v=vendors.find(x=>x.id===row.vendor_id);
      if(v&&typeof row.lat==='number'&&typeof row.lng==='number'){
        v.location={lat:row.lat,lng:row.lng};
        if(row.market)v.market=row.market;
        changed=true;
      }
    });
    if(changed&&typeof render==='function')render();
  }catch(e){ /* silencioso */ }
}
function initSupabase(){
  if(!supabaseReady())return;
  ensureSupabase()
    .then(()=>{ console.log('[MercApp] Conectado a Supabase'); loadMarketsCloud(); restoreSupabaseSession(); })
    .catch(err=>console.warn('[MercApp] Supabase no disponible:', err));
}
