function applySupaUser(user){
  if(!user||state.vendorLoggedIn)return;     // no pisar sesión de vendedor
  const email=(user.email||'').toLowerCase();
  const md=user.user_metadata||{};
  state.role='cliente'; state.authed=true; state.vendorLoggedIn=false;
  state.isAdmin=isAdminEmail(email);
  state.currentAccount=email;
  state.clientProfile=clone(DEFAULT_PROFILE);
  const fn=(md.full_name||md.name||'').trim();
  if(md.nombre||md.apellido){ state.clientProfile.nombre=md.nombre||''; state.clientProfile.apellido=md.apellido||''; }
  else if(fn){ const p=fn.split(' '); state.clientProfile.nombre=p.shift()||''; state.clientProfile.apellido=p.join(' '); }
  if(md.direccion)state.clientProfile.direccion=md.direccion;
  if(md.dni)state.clientProfile.dni=md.dni;
  if(md.tel1)state.clientProfile.tel1=md.tel1;
  if(md.avatar_url||md.picture)state.clientProfile.photoImg=md.avatar_url||md.picture;
  closeModal(); render();
}
let _supaAuthBound=false;
async function restoreSupabaseSession(){
  if(!supabaseReady())return;
  try{
    const c=await ensureSupabase();
    const {data}=await c.auth.getSession();
    if(data&&data.session&&data.session.user){ applySupaUser(data.session.user); }
    if(!_supaAuthBound){
      _supaAuthBound=true;
      c.auth.onAuthStateChange((ev,session)=>{
        if(ev==='SIGNED_IN'&&session&&session.user){ applySupaUser(session.user); toast(state.isAdmin?'Sesión de administrador':'Sesión iniciada con Google'); }
      });
    }
  }catch(e){}
}

