/* ===== Cuentas de usuario (registro "Crear cuenta") =====
   FASE ACTUAL: se guardan en localStorage del navegador, por lo que persisten
   entre sesiones y se restauran al iniciar sesión nuevamente.
   FASE FUTURA: reemplazar por Firebase Auth/Firestore o Supabase Auth, p. ej.:
     Supabase: await supabase.auth.signUp({email,password}); insert en tabla 'profiles'.
     Firebase: createUserWithEmailAndPassword(auth,email,password); setDoc(doc(db,'users',uid),profile).
   Nota: en producción la contraseña NO se almacena en texto plano; la gestiona el
   proveedor de autenticación. Aquí es solo demostración local. */
const AccountsRepo={
  KEY:'mercapp_accounts',
  _mem:{},
  _load(){ try{return JSON.parse(localStorage.getItem(this.KEY)||'{}');}catch(e){return this._mem;} },
  _save(o){ try{localStorage.setItem(this.KEY,JSON.stringify(o));}catch(e){this._mem=o;} },
  list(){ return this._load(); },
  find(email){ return this._load()[(email||'').toLowerCase()]||null; },
  exists(email){ return !!this.find(email); },
  create(acc){ const all=this._load(); all[acc.email.toLowerCase()]=acc; this._save(all); },
  update(email,patch){ const all=this._load(),e=(email||'').toLowerCase(); if(all[e]){all[e]={...all[e],...patch};this._save(all);} }
};

