/* notificaciones de mensajes no leídos */
function unreadFor(role,vendorId){
  const v=vendors.find(x=>x.id===vendorId); if(!v)return 0;
  const target=role==='vendedor'?'cliente':'vendedor';
  return v.msgs.filter(m=>m.from===target && !m.read).length;
}
function totalUnread(){
  if(state.role==='vendedor'){return unreadFor('vendedor',state.myVendorId);}
  return vendors.reduce((s,v)=>s+unreadFor('cliente',v.id),0);
}

/* ---------------- HELPERS ---------------- */
const $=s=>document.querySelector(s);
function toast(t){const r=$('#toastRoot');r.innerHTML=`<div class="toast">${t}</div>`;setTimeout(()=>r.innerHTML='',2200);}
function money(n){return 'S/ '+n.toFixed(2).replace(/\.00$/,'.00');}
function shipping(total){
  if(total<=0)return 0;
  if(total<30)return 5.5;
  if(total<100)return 10;
  if(total<200)return 15;
  if(total<300)return 20;
  if(total<400)return 30;
  const band=Math.floor(total/100);      // 400-499 -> 4
  return 30+(band-3)*10;                  // sigue subiendo 10 por cada 100
}
const IGV_RATE=0.18;
function orderTotals(){
  const sub=state.cart.reduce((s,i)=>s+i.total,0);
  const igv=sub*IGV_RATE;
  const delivery=(state.deliveryMode==='delivery') ? shipping(sub) : 0;
  return {sub,igv,delivery,total:sub+igv+delivery};
}
function summaryBlock(t,isDelivery){
  return `<div class="paysummary">
    <div class="row" style="justify-content:space-between"><span class="muted">Subtotal</span><b>${money(t.sub)}</b></div>
    <div class="row" style="justify-content:space-between;margin-top:6px"><span class="muted">IGV (18%)</span><b>${money(t.igv)}</b></div>
    ${isDelivery?`<div class="row" style="justify-content:space-between;margin-top:6px"><span class="muted">Delivery</span><b>${money(t.delivery)}</b></div>`:''}
    <div class="row paytotal" style="justify-content:space-between;margin-top:10px"><b>Total</b><b style="color:var(--green)">${money(t.total)}</b></div>
  </div>`;
}
function setDeliveryMode(m){ state.deliveryMode=m; render(); }
function dist(a,b){ // distancia en km entre {lat,lng} (Haversine)
  const R=6371, toR=d=>d*Math.PI/180;
  const dLat=toR(b.lat-a.lat), dLng=toR(b.lng-a.lng);
  const x=Math.sin(dLat/2)**2 + Math.cos(toR(a.lat))*Math.cos(toR(b.lat))*Math.sin(dLng/2)**2;
  return 2*R*Math.asin(Math.sqrt(x));
}
const RADIUS_KM=2.5;
const LIMA={center:[-11.9900,-77.0600], zoom:13}; // Lima Metropolitana — vista hacia Lima Norte

function nearbyVendorIds(){
  if(!state.clientLocation)return vendors.map(v=>v.id); // sin ubicación -> todos
  return vendors.filter(v=>dist(v.location,state.clientLocation)<=RADIUS_KM).map(v=>v.id);
}

function visibleProducts(applySearch=true){
  let list=products.slice();
  if(state.role==='cliente'){
    const near=nearbyVendorIds();
    list=list.filter(p=>near.includes(p.v));
  }
  if(applySearch && state.search.trim()){
    const q=state.search.toLowerCase();
    list=list.filter(p=>p.name.toLowerCase().includes(q));
  }
  return sortList(list);
}
function sortList(list){
  const s=state.sort;
  if(s==='alpha-asc')  return list.slice().sort((a,b)=>a.name.localeCompare(b.name));
  if(s==='alpha-desc') return list.slice().sort((a,b)=>b.name.localeCompare(a.name));
  if(s==='price-desc') return list.slice().sort((a,b)=>b.price-a.price);
  if(s==='price-asc')  return list.slice().sort((a,b)=>a.price-b.price);
  return list;  // 'none'
}
function groupByCat(list){
  const map={};
  list.forEach(p=>{(map[p.cat]=map[p.cat]||[]).push(p);});
  return CATEGORIES.filter(c=>map[c.id]&&map[c.id].length).map(c=>({cat:c,items:map[c.id]}));
}
/* Render del grid: plano, o agrupado por categorías (▦) — el orden A–Z/Precio se aplica dentro de cada grupo */
function productsGrid(list, showVendor, uniform){
  const cardOf=p=>productCard(p, showVendor, uniform);
  const cls='grid'+(uniform?' grid-uniform':'');
  if(state.groupCats){
    const groups=groupByCat(list);
    if(!groups.length) return `<div class="empty">No hay productos para mostrar.</div>`;
    return groups.map(g=>`<div class="catgroup"><h3 class="catgroup-h">${g.cat.emoji} ${g.cat.name} <span>${g.items.length}</span></h3><div class="${cls}">${sortList(g.items).map(cardOf).join('')}</div></div>`).join('');
  }
  return `<div class="${cls}">${sortList(list).map(cardOf).join('')}</div>`;
}

