/* Popup al cancelar el pedido: datos editables + QR + Cancelar + Verificar */
function orderData(){
  const cp=state.clientProfile||{};
  const a=($('#ckAddr')&&$('#ckAddr').value.trim())||(_lastOrder&&_lastOrder.a)||cp.direccion||'';
  const d=($('#ckDni')&&$('#ckDni').value.trim())||(_lastOrder&&_lastOrder.dni)||cp.dni||'';
  const tel=($('#ckTel')&&$('#ckTel').value.trim())||(_lastOrder&&_lastOrder.tel)||cp.tel1||'';
  const n=($('#ckName')&&$('#ckName').value.trim())||(_lastOrder&&_lastOrder.n)||clientFullName();
  return {a,d,n,tel};
}
function openYapeCancel(){
  const isDelivery = (_lastOrder? _lastOrder.mode : state.deliveryMode)==='delivery';
  const {a,d,n,tel}=orderData();
  const fields = isDelivery
    ? `<div style="text-align:left">
        <label class="fld">Dirección de envío</label><input class="inp" id="cyAddr" value="${escAttr(a)}">
        <label class="fld">DNI</label><input class="inp" id="cyDni" maxlength="8" inputmode="numeric" value="${escAttr(d)}">
        <label class="fld">Celular</label><input class="inp" id="cyTel" maxlength="12" inputmode="numeric" value="${escAttr(tel)}">
        <label class="fld">Nombre del receptor</label><input class="inp" id="cyName" value="${escAttr(n)}">
      </div>`
    : `<div style="text-align:left">
        <div class="stat" style="width:100%">🏪 Recojo en tienda · sin dirección ni delivery.</div>
        <label class="fld">Teléfono</label><input class="inp" id="cyTel" maxlength="12" inputmode="numeric" value="${escAttr(tel)}">
        <label class="fld">DNI</label><input class="inp" id="cyDni" maxlength="8" inputmode="numeric" value="${escAttr(d)}">
        <label class="fld">Nombre</label><input class="inp" id="cyName" value="${escAttr(n)}">
      </div>`;
  modal(`<div class="modal yape-modal" style="max-width:380px"><div class="modal-body" style="text-align:center">
    <h2 style="font-size:20px;margin:0 0 4px">¿Cancelar el pedido?</h2>
    <p class="muted" style="font-size:13px;margin:0 0 10px">Revisa o edita tus datos. Si ya pagaste con Yape, pulsa <b>Verificar</b>.</p>
    ${fields}
    <img src="${YAPE_QR}" alt="Código QR de Yape" class="yape-qr" style="margin-top:12px">
    <div class="row" style="margin-top:14px;gap:10px">
      <button class="btn ghost" style="flex:1;color:var(--orange);border-color:var(--orange)" onclick="cancelOrder()">Cancelar</button>
      <button class="btn" style="flex:1" onclick="verifyFromCancel()">Verificar</button>
    </div>
  </div></div>`);
}
function verifyFromCancel(){
  const isDelivery = (_lastOrder? _lastOrder.mode : state.deliveryMode)==='delivery';
  const n=($('#cyName')&&$('#cyName').value.trim())||clientFullName()||'Cliente';
  const tel=($('#cyTel')&&$('#cyTel').value.trim())||'';
  const t=orderTotals();
  const items=(_lastOrder&&_lastOrder.items&&_lastOrder.items.length)?_lastOrder.items:cartSnapshot();
  if(isDelivery){
    const a=$('#cyAddr')?$('#cyAddr').value.trim():'';
    const d=$('#cyDni')?$('#cyDni').value.trim():'';
    if(!a){toast('Ingresa la dirección de envío');return;}
    if(d.length!==8){toast('El DNI debe tener 8 dígitos');return;}
    if(telDigits(tel).length!==9){toast('El celular debe tener 9 dígitos');return;}
    saveOrderToProfile({a,d,tel,isDelivery:true});
    _lastOrder={mode:'delivery',a,n,tel,dni:d,items,...t};
  }else{
    const d=$('#cyDni')?$('#cyDni').value.trim():'';
    if(telDigits(tel).length<6){toast('Ingresa un teléfono válido');return;}
    if(d.length!==8){toast('El DNI debe tener 8 dígitos');return;}
    saveOrderToProfile({d,tel,isDelivery:false});
    _lastOrder={mode:'pickup',a:'Recojo en tienda',n,tel,dni:d,items,...t};
  }
  finishOrder();
}
function saveOrderToProfile(o){
  if(!state.clientProfile||!o)return;
  const upd={};
  if(o.tel){state.clientProfile.tel1=o.tel; upd.tel1=o.tel;}
  if(o.d){state.clientProfile.dni=o.d; upd.dni=o.d;}
  if(o.isDelivery&&o.a){state.clientProfile.direccion=o.a; upd.direccion=o.a;}
  if(state.currentAccount&&Object.keys(upd).length)AccountsRepo.update(state.currentAccount,upd);
}
function cancelOrder(){_lastOrder=null;state.cart=[];closeModal();go('home');toast('Pedido cancelado');}

/* ================= ADMIN · Personalización de colores ================= */
/* Solo disponible para el administrador (login 456456). */
const CE_VARS=[
  {v:'--green',     label:'Verde principal',    seed:'#1f7a44'},
  {v:'--orange',    label:'Naranja (acento)',   seed:'#e8732c'},
  {v:'--bg',        label:'Fondo de página',    seed:'#fbf8f1'},
  {v:'--surface',   label:'Tarjetas / paneles', seed:'#ffffff'},
  {v:'--ink',       label:'Texto',              seed:'#1b211c'},
  {v:'--line',      label:'Bordes',             seed:'#e7e2d6'},
  {v:'--green-deep',label:'Verde oscuro (hover)',seed:'#13502d'},
];
const PALETTE_CIRCLE=['#1f7a44','#2fa05c','#e8732c','#d64545','#2563eb','#7c3aed','#0891b2','#1b211c','#fbf8f1'];
const PALETTE_RECT=['#0f5132','#198754','#20c997','#ffc107','#fd7e14','#dc3545','#6f42c1','#0dcaf0','#212529','#6c757d','#adb5bd','#f8f9fa'];

let CE={v:'--green',h:0,s:0,l:0,a:1};

/* Persistencia de la paleta (global, visible para todos los roles).
   FASE ACTUAL: en memoria de la página (persiste entre cambios de rol y de sesión de login).
   FASE FUTURA (online): reemplazar save()/load() por Firebase o Supabase, p. ej.:
     async save(c){ await supabase.from('config').upsert({id:'theme',colors:c}); }
     async load(){ const {data}=await supabase.from('config').select('colors').eq('id','theme').single(); return data?.colors||{}; }
   o con Firestore: setDoc(doc(db,'config','theme'),{colors:c}) / getDoc(...). */
const ThemeRepo={
  _data:{},
  save(colors){ this._data=JSON.parse(JSON.stringify(colors)); },
  load(){ return this._data; }
};
function applyColors(colors){
  Object.entries(colors||{}).forEach(([v,c])=>{
    document.documentElement.style.setProperty(v, `hsla(${c.h}, ${c.s}%, ${c.l}%, ${c.a})`);
  });
}

function hexToHsl(hex){
  hex=(hex||'').replace('#','');
  if(hex.length===3)hex=hex.split('').map(c=>c+c).join('');
  const r=parseInt(hex.slice(0,2),16)/255,g=parseInt(hex.slice(2,4),16)/255,b=parseInt(hex.slice(4,6),16)/255;
  const mx=Math.max(r,g,b),mn=Math.min(r,g,b);let h=0,s=0,l=(mx+mn)/2;
  if(mx!==mn){const d=mx-mn;s=l>.5?d/(2-mx-mn):d/(mx+mn);
    if(mx===r)h=(g-b)/d+(g<b?6:0);else if(mx===g)h=(b-r)/d+2;else h=(r-g)/d+4;h/=6;}
  return {h:Math.round(h*360),s:Math.round(s*100),l:Math.round(l*100)};
}
function hslToHex(h,s,l){
  s/=100;l/=100;const a=s*Math.min(l,1-l);
  const f=n=>{const k=(n+h/30)%12;return l-a*Math.max(-1,Math.min(k-3,9-k,1));};
  const to=x=>Math.round(255*x).toString(16).padStart(2,'0');
  return '#'+to(f(0))+to(f(8))+to(f(4));
}
function cssOf(c){return `hsla(${c.h}, ${c.s}%, ${c.l}%, ${c.a})`;}

function ceLoad(v){
  CE.v=v;
  const stored=state.adminColors[v];
  if(stored){CE={v,...stored};}
  else{const def=CE_VARS.find(x=>x.v===v),c=hexToHsl(def.seed);CE={v,h:c.h,s:c.s,l:c.l,a:1};}
}
function openColorEditor(){ if(!state.isAdmin)return; ceLoad(CE.v||'--green'); modal(colorEditorHTML()); }
function refreshCE(){ modal(colorEditorHTML()); }
function colorEditorHTML(){
  const hex=hslToHex(CE.h,CE.s,CE.l);
  const opts=CE_VARS.map(x=>`<option value="${x.v}" ${x.v===CE.v?'selected':''}>${x.label}</option>`).join('');
  const circ=PALETTE_CIRCLE.map(c=>`<button class="sw circ" style="background:${c}" title="${c}" onclick="ceSwatch('${c}')"></button>`).join('');
  const rect=PALETTE_RECT.map(c=>`<button class="sw rect" style="background:${c}" title="${c}" onclick="ceSwatch('${c}')"></button>`).join('');
  return `<div class="modal" style="max-width:480px"><div class="modal-body">
    <button class="closex" style="position:static;float:right;background:var(--line);color:var(--ink)" onclick="closeModal()">✕</button>
    <h2>🎨 Personalización de colores</h2>
    <p class="muted" style="margin:2px 0 0;font-size:13px">Exclusivo del administrador · cambia el color de cada elemento de la página.</p>
    <label class="fld">Elemento de la página</label>
    <select class="inp" id="ceVar" onchange="ceLoad(this.value);refreshCE()">${opts}</select>
    <div class="cepreview"><span class="cechip" id="ceChip" style="background-color:${cssOf(CE)}"></span><b id="ceHexLbl">${hex}</b></div>
    <label class="fld">Paleta circular</label><div class="swrow">${circ}</div>
    <label class="fld">Paleta rectangular</label><div class="swgrid">${rect}</div>
    <label class="fld">Color (matiz) · <span id="ceHv">${CE.h}°</span></label>
    <input type="range" class="rng hue" id="ceH" min="0" max="360" value="${CE.h}" oninput="ceSlide()">
    <label class="fld">Saturación · <span id="ceSv">${CE.s}%</span></label>
    <input type="range" class="rng" id="ceS" min="0" max="100" value="${CE.s}" oninput="ceSlide()">
    <label class="fld">Transparencia · <span id="ceAv">${Math.round(CE.a*100)}%</span></label>
    <input type="range" class="rng" id="ceA" min="0" max="100" value="${Math.round(CE.a*100)}" oninput="ceSlide()">
    <label class="fld">Código hexadecimal</label>
    <div class="row" style="gap:8px"><input class="inp" id="ceHex" value="${hex}" style="flex:1" placeholder="#FF5733" onchange="ceFromHex(this.value)"><button class="btn sm" onclick="ceFromHex($('#ceHex').value)">Aplicar</button></div>
    <div class="row" style="margin-top:16px;gap:10px">
      <button class="btn" style="flex:1" onclick="closeModal()">Listo</button>
      <button class="btn ghost" onclick="ceReset()">↺ Restaurar valores predeterminados</button>
    </div>
  </div></div>`;
}
function ceApply(){
  const css=cssOf(CE);
  document.documentElement.style.setProperty(CE.v,css);
  state.adminColors[CE.v]={h:CE.h,s:CE.s,l:CE.l,a:CE.a};
  ThemeRepo.save(state.adminColors);   // se guarda para todos los roles
  const hex=hslToHex(CE.h,CE.s,CE.l);
  const chip=$('#ceChip'); if(chip)chip.style.backgroundColor=css;
  const hl=$('#ceHexLbl'); if(hl)hl.textContent=hex;
  const hi=$('#ceHex'); if(hi)hi.value=hex;
}
function ceSlide(){
  CE.h=+$('#ceH').value; CE.s=+$('#ceS').value; CE.a=+$('#ceA').value/100;
  $('#ceHv').textContent=CE.h+'°'; $('#ceSv').textContent=CE.s+'%'; $('#ceAv').textContent=Math.round(CE.a*100)+'%';
  ceApply();
}
function ceFromHex(val){
  val=(val||'').trim();
  if(!/^#?[0-9a-fA-F]{3}([0-9a-fA-F]{3})?$/.test(val)){toast('Hex inválido (ej. #FF5733)');return;}
  const c=hexToHsl(val);CE.h=c.h;CE.s=c.s;CE.l=c.l; // alpha se conserva
  ceApply();refreshCE();
}
function ceSwatch(hex){const c=hexToHsl(hex);CE.h=c.h;CE.s=c.s;CE.l=c.l;ceApply();refreshCE();}
function ceReset(){
  Object.keys(state.adminColors).forEach(v=>document.documentElement.style.removeProperty(v));
  state.adminColors={};ThemeRepo.save({});toast('Valores predeterminados restaurados');ceLoad(CE.v);refreshCE();
}
