/* ================= MAPA · OpenStreetMap + Leaflet ================= */
/* Capa de datos: hoy local; preparada para Firebase/Supabase en producción */
const MarketsRepo={
  // FASE ACTUAL (prototipo offline): datos de prueba locales
  list(){ return vendors.map(v=>({id:v.id,name:v.company,logo:v.logo,lat:v.location.lat,lng:v.location.lng})); },
  // FASE FUTURA (online): reemplazar por una consulta a la base de datos, p. ej.:
  //   async list(){ const {data}=await supabase.from('markets').select('*'); return data; }
  //   async list(){ const snap=await getDocs(collection(db,'markets')); return snap.docs.map(d=>d.data()); }
};

let _map=null, _refresh=null, _setSel=null;

/* Carga diferida de Leaflet: solo se descarga al abrir un mapa (mejora el arranque) */
let _leafletLoading=false, _leafletCbs=[];
function ensureLeaflet(cb){
  if(window.L){cb();return;}
  _leafletCbs.push(cb);
  if(_leafletLoading)return;
  _leafletLoading=true;
  const link=document.createElement('link');
  link.rel='stylesheet'; link.href='https://unpkg.com/leaflet@1.9.4/dist/leaflet.css';
  document.head.appendChild(link);
  const s=document.createElement('script');
  s.src='https://unpkg.com/leaflet@1.9.4/dist/leaflet.js';
  s.onload=()=>{const cbs=_leafletCbs;_leafletCbs=[];cbs.forEach(f=>f());};
  s.onerror=()=>{_leafletLoading=false;const el=document.getElementById('leafmap');if(el)el.innerHTML='<div class="maperr">No se pudo cargar el mapa. Revisa tu conexión a internet.</div>';};
  document.head.appendChild(s);
}

function destroyMap(){ clearGeoWatch(); if(_map){try{_map.remove();}catch(e){} _map=null;_refresh=null;_setSel=null;} }

function buildMap(mode, vendorId, listElId, onPick){
  if(typeof L==='undefined'){
    document.getElementById('leafmap').innerHTML='<div class="maperr">No se pudo cargar OpenStreetMap.<br>Conéctate a internet para ver el mapa (Leaflet se carga por CDN).</div>';
    return;
  }
  const startLoc = (mode==='cliente') ? state.clientLocation
                 : vendors.find(v=>v.id===vendorId).location;
  const center = startLoc ? [startLoc.lat,startLoc.lng] : LIMA.center;

  destroyMap();
  _map = L.map('leafmap').setView(center, startLoc?15:LIMA.zoom);
  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',{
    maxZoom:19, attribution:'&copy; OpenStreetMap'
  }).addTo(_map);

  const marketLayer=L.layerGroup().addTo(_map);
  let selMarker=null, ring=null;
  let selected = startLoc ? {lat:startLoc.lat,lng:startLoc.lng} : null;
  let searchOn = (mode!=='cliente');  // el cliente activa la búsqueda al tocar el muñeco

  // marcador "muñeco" animado para la ubicación del cliente
  const meIcon=L.divIcon({className:'me-pin',html:'<div class="me-pulse"></div><div class="me-bob">🧍</div>',iconSize:[30,34],iconAnchor:[15,30],popupAnchor:[0,-28]});
  // marcador del vendedor: imagen del personaje vendedor
  const vendorIcon=L.divIcon({className:'vendor-pin',html:`<div class="vendor-bob" style="background-image:url(${VENDOR_IMG})"></div>`,iconSize:[54,68],iconAnchor:[27,64],popupAnchor:[0,-60]});

  function refresh(){
    marketLayer.clearLayers();
    if(ring){_map.removeLayer(ring);ring=null;}
    if(selMarker){_map.removeLayer(selMarker);selMarker=null;}
    let near=[];
    const showResults = !!selected && (mode!=='cliente' || searchOn);
    if(selected){
      if(mode==='cliente'){
        selMarker=L.marker([selected.lat,selected.lng],{icon:meIcon}).addTo(_map)
          .bindPopup(searchOn?'🧍 Tú · mostrando mercados a 2.5 km':'🧍 Tú · toca para buscar mercados a 2.5 km');
        selMarker.on('click',()=>{ searchOn=true; refresh(); });
      }else{
        selMarker=L.marker([selected.lat,selected.lng],{icon:vendorIcon,draggable:true}).addTo(_map)
          .bindPopup('📍 Aquí está tu mercado · arrástrame para ajustar');
        selMarker.on('dragend',ev=>{const ll=ev.target.getLatLng();setSelected({lat:ll.lat,lng:ll.lng});});
      }
    }
    if(showResults){
      ring=L.circle([selected.lat,selected.lng],{radius:RADIUS_KM*1000,color:'#1f7a44',weight:2,fillColor:'#1f7a44',fillOpacity:.12}).addTo(_map);
      near=MarketsRepo.list().filter(m=>dist(selected,m)<=RADIUS_KM)
                             .sort((a,b)=>dist(selected,a)-dist(selected,b));
      near.forEach(m=>{
        const ic=L.divIcon({className:'mkt-pin-wrap',html:`<div class="mkt-pin">${m.logo||'🏪'}</div>`,iconSize:[32,32],iconAnchor:[16,16],popupAnchor:[0,-14]});
        L.marker([m.lat,m.lng],{icon:ic}).addTo(marketLayer)
          .bindPopup(`<b>${m.logo} ${m.name}</b><br>${dist(selected,m).toFixed(2)} km`);
      });
    }
    renderList(near, showResults);
  }
  function renderList(near, showResults){
    const el=listElId&&document.getElementById(listElId); if(!el)return;
    if(!selected){el.innerHTML='<div class="muted" style="padding:10px">'+(mode==='cliente'?'Permite el acceso a tu ubicación o toca el mapa para fijarla.':'Toca el mapa para fijar la ubicación de tu mercado.')+'</div>';return;}
    if(mode==='cliente' && !showResults){el.innerHTML='<div class="muted" style="padding:10px">Toca el muñeco 🧍 en el mapa para buscar mercados a 2.5 km.</div>';return;}
    if(!near.length){el.innerHTML='<div class="muted" style="padding:10px">No hay mercados dentro de 2.5 km. Prueba otra ubicación.</div>';return;}
    el.innerHTML=`<div class="mlhead">${near.length} mercado(s) a ≤ 2.5 km</div>`+
      near.map(m=>`<div class="mlrow"><span>${m.logo} ${m.name}</span><b>${dist(selected,m).toFixed(2)} km</b></div>`).join('');
  }

  function setSelected(loc){ selected=loc; if(onPick)onPick(loc); refresh(); }
  _refresh=refresh; _setSel=setSelected;

  _map.on('click', e=>setSelected({lat:e.latlng.lat,lng:e.latlng.lng}));
  setTimeout(()=>{ if(_map)_map.invalidateSize(); }, 180);
  refresh();
}

/* Permiso de ubicación (PC, Android, iOS) + seguimiento en tiempo real */
let _geoWatch=null;
function clearGeoWatch(){ if(_geoWatch!=null && navigator.geolocation){try{navigator.geolocation.clearWatch(_geoWatch);}catch(e){}} _geoWatch=null; }
function requestLocation(){
  if(!navigator.geolocation){toast('Geolocalización no disponible en este navegador');return;}
  toast('Solicitando permiso de ubicación…');
  let firstFix=true;
  clearGeoWatch();
  _geoWatch=navigator.geolocation.watchPosition(
    p=>{
      const loc={lat:p.coords.latitude,lng:p.coords.longitude};
      if(_setSel)_setSel(loc);
      if(firstFix){ firstFix=false; if(_map)_map.setView([loc.lat,loc.lng],16); toast('Ubicación encontrada · toca el muñeco 🧍'); }
    },
    err=>{ toast(err && err.code===1 ? 'Permiso de ubicación denegado' : 'No se pudo obtener tu ubicación'); },
    {enableHighAccuracy:true, maximumAge:5000, timeout:12000}
  );
}

