function editLogo(id){pickImage(d=>{vendors.find(v=>v.id===id).logoImg=d;render();toast('Imagen de empresa actualizada');});}

/* banner principal: drag & drop (admin) */
function bindBanner(){
  const b=$('#homeBanner');if(!b)return;
  ['dragover','dragenter'].forEach(ev=>b.addEventListener(ev,e=>{e.preventDefault();b.classList.add('drag');}));
  ['dragleave','drop'].forEach(ev=>b.addEventListener(ev,e=>{e.preventDefault();b.classList.remove('drag');}));
  b.addEventListener('drop',e=>{
    if(!state.isAdmin){toast('Solo el administrador puede cambiar el banner principal');return;}
    const f=e.dataTransfer.files[0];if(!f||!f.type.startsWith('image'))return;
    const rd=new FileReader();rd.onload=ev=>{state.bannerImg=ev.target.result;render();toast('Banner principal actualizado (admin)');};rd.readAsDataURL(f);});
}

/* ---------------- AUTH & NAV ---------------- */
async function doLogin(){
  const u=($('#lu').value||'').trim().toLowerCase(), p=($('#lp').value||'').trim();
  const role=state.loginRole;
  state.search=''; state.vendorEditing=false; state._vendorBackup=null;
  if(role==='vendedor'){
    const c=VENDOR_CREDS[u];
    if(c&&c.pass===p){
      state.role='vendedor'; state.vendorLoggedIn=true; state.myVendorId=c.id; state.isAdmin=false;
      state.authed=false; state._pending=null;
      closeModal(); go('vendor',c.id); toast('Sesión iniciada · bienvenido');
    }else toast('Usuario o contraseña incorrectos');
    return;
  }
  // CLIENTE — credenciales demo (funcionan sin conexión)
  if(u==='789789@mercapp.com'&&p==='789789'){ loginClient(false,null); return; }
  if(u==='456456@mercapp.com'&&p==='456456'){ loginClient(true,null);  return; }  // admin demo
  // Cuenta real en Supabase
  if(supabaseReady()){
    try{
      const {data,error}=await supaSignIn(u,p);
      if(!error&&data&&data.user){
        applySupaUser(data.user);
        toast(state.isAdmin?'Sesión de administrador':'Sesión iniciada');
        const next=state._pending; state._pending=null; if(typeof next==='function')next();
        return;
      }
      if(error&&error.message&&/confirm/i.test(error.message)){ toast('Confirma tu correo antes de ingresar'); return; }
    }catch(e){}
  }
  // Cuenta local registrada (respaldo)
  const acc=AccountsRepo.find(u);
  if(acc&&acc.password===p){ loginClient(false,acc); return; }
  toast('Usuario o contraseña incorrectos');
}
function loginClient(admin,accProfile){
  state.role='cliente'; state.authed=true; state.isAdmin=admin; state.vendorLoggedIn=false;
  if(accProfile) loadAccountProfile(accProfile);
  else { state.currentAccount=null; state.clientProfile=clone(DEFAULT_PROFILE); }
  closeModal();
  toast(admin?'Sesión de administrador':'Sesión iniciada · bienvenido');
  const next=state._pending; state._pending=null;
  if(typeof next==='function') next(); else render();
}
function loadAccountProfile(acc){
  state.clientProfile={
    banner:null, photo:'🙂', photoImg:acc.photoImg||null,
    nombre:acc.nombre||'', apellido:acc.apellido||'',
    direccion:acc.direccion||'', dni:acc.dni||'',
    tel1:acc.tel1||'', tel2:acc.tel2||'', payment:acc.payment||'Efectivo', orders:acc.orders||[]
  };
  state.currentAccount=acc.email.toLowerCase();
}
function confirmLogout(){
  modal(`<div class="modal" style="max-width:360px"><div class="modal-body" style="text-align:center">
    <div style="font-size:46px">👋</div>
    <h2 style="font-size:22px">¿Quieres salir de tu cuenta?</h2>
    <div class="row" style="margin-top:16px;gap:10px">
      <button class="btn" style="flex:1" onclick="logout()">Sí, salir</button>
      <button class="btn ghost" style="flex:1" onclick="closeModal()">No</button>
    </div>
  </div></div>`);
}
function logout(){
  supaSignOut();
  state.authed=false; state.vendorLoggedIn=false; state.isAdmin=false;
  state.vendorEditing=false; state._vendorBackup=null;
  state.currentAccount=null; state.clientProfile=clone(DEFAULT_PROFILE);
  state.role='cliente'; state.cart=[]; state.search=''; state.view='home'; state.category=null;
  closeModal(); render(); toast('Sesión cerrada');
  openLoginModal('cliente');     // regresa al login
}

function go(view,vendorId){
  // el vendedor no accede a vistas de cliente
  if(state.role==='vendedor'&&state.vendorLoggedIn&&['home','categories','cart','checkout','clientprofile'].includes(view)){
    view='vendor'; vendorId=state.myVendorId;
  }
  state.view=view;if(vendorId!=null)state.viewVendorId=vendorId;
  if(view==='home'||view==='categories')state.category=null;
  closeModal();window.scrollTo({top:0,behavior:'smooth'});render();
}
function onSearch(v){state.search=v;state.category=null;if(state.view!=='home'&&state.view!=='vendor')go('home');else render();}
function toggleTheme(){state.theme=state.theme==='light'?'dark':'light';document.documentElement.setAttribute('data-theme',state.theme);refreshChrome();}

let _lastOrder=null, _lastReceipt=null;
function cartSnapshot(){ return state.cart.map(i=>({name:i.name,kilos:i.kilos,price:i.price,total:i.total,vendor:i.vendor||'',market:i.market||''})); }
function telDigits(v){ return (v||'').replace(/\D/g,''); }
function greetingByHour(){
  const h=new Date().getHours();
  if(h>=5 && h<12)  return 'Gracias por su compra, tenga un excelente día.';
  if(h>=12 && h<19) return 'Gracias por su compra, tenga una excelente tarde.';
  return 'Gracias por su compra, tenga una excelente noche.';
}
function confirmOrder(){
  const isDelivery = state.deliveryMode==='delivery';
  const n=($('#ckName')&&$('#ckName').value.trim())||clientFullName()||'Cliente';
  const tel=($('#ckTel')&&$('#ckTel').value.trim())||'';
  const t=orderTotals();
  if(isDelivery){
    const a=($('#ckAddr')&&$('#ckAddr').value.trim())||'';
    const d=($('#ckDni')&&$('#ckDni').value.trim())||'';
    if(!a){toast('Ingresa la dirección de envío');return;}
    if(d.length!==8){toast('El DNI debe tener 8 dígitos');return;}
    if(telDigits(tel).length!==9){toast('El celular debe tener 9 dígitos');return;}
    saveOrderToProfile({a,d,tel,isDelivery:true});
    _lastOrder={mode:'delivery',a,n,tel,dni:d,items:cartSnapshot(),...t};
  }else{
    const d=($('#ckDni')&&$('#ckDni').value.trim())||'';
    if(telDigits(tel).length<6){toast('Ingresa un teléfono válido');return;}
    if(d.length!==8){toast('El DNI debe tener 8 dígitos');return;}
    saveOrderToProfile({d,tel,isDelivery:false});
    _lastOrder={mode:'pickup',a:'Recojo en tienda',n,tel,dni:d,items:cartSnapshot(),...t};
  }
  openYapeQR(true);   // muestra el QR de Yape para pagar
}
function finishOrder(){
  const o=_lastOrder||{mode:state.deliveryMode,a:'tu pedido',n:'ti',items:cartSnapshot(),...orderTotals()};
  if(!o.items||!o.items.length) o.items=cartSnapshot();
  const isDelivery=o.mode==='delivery';
  _lastReceipt={...o, payment:'Yape', when:Date.now(), greeting:greetingByHour()};
  if(state.clientProfile){
    state.clientProfile.orders = state.clientProfile.orders||[];
    state.clientProfile.orders.unshift(_lastReceipt);
    if(state.currentAccount) AccountsRepo.update(state.currentAccount,{orders:state.clientProfile.orders});
  }
  _lastOrder=null;state.cart=[];
  modal(`<div class="modal" style="max-width:420px"><div class="modal-body" style="text-align:center">
    <div style="font-size:60px">✅</div><h2>¡Pago verificado!</h2>
    <p class="muted">${isDelivery?`Tu pedido será enviado a <b>${escapeHtml(o.a)}</b> a nombre de <b>${escapeHtml(o.n)}</b>.`:`Recoge tu pedido en la tienda del vendedor (a nombre de <b>${escapeHtml(o.n)}</b>).`}</p>
    <div class="paysummary" style="text-align:left;margin-top:12px">
      <div class="row" style="justify-content:space-between"><span class="muted">Subtotal</span><b>${money(o.sub)}</b></div>
      <div class="row" style="justify-content:space-between;margin-top:6px"><span class="muted">IGV (18%)</span><b>${money(o.igv)}</b></div>
      ${isDelivery?`<div class="row" style="justify-content:space-between;margin-top:6px"><span class="muted">Delivery</span><b>${money(o.delivery)}</b></div>`:''}
      <div class="row paytotal" style="justify-content:space-between;margin-top:10px"><b>Total pagado</b><b style="color:var(--green)">${money(o.total)}</b></div>
    </div>
    <p style="margin-top:12px;font-style:italic;color:var(--green)">${_lastReceipt.greeting}</p>
    <button class="btn block" style="margin-top:12px" onclick="downloadBoleta()">📄 Descargar boleta</button>
    <button class="btn ghost block" style="margin-top:10px" onclick="closeModal();go('home')">Seguir comprando</button>
  </div></div>`);
}
/* Genera y descarga la boleta de venta (HTML imprimible) */
function storeShort(name){ if(!name)return''; return name.length>24?name.slice(0,22)+'…':name; }
function b64encUTF8(str){ return btoa(unescape(encodeURIComponent(str))); }
function b64decUTF8(b){ return decodeURIComponent(escape(atob(b))); }
/* QR (carga diferida de un generador local; los datos no salen del navegador) */
let _qrLoading=false,_qrCbs=[];
function ensureQR(cb){
  if(window.qrcode){cb();return;}
  _qrCbs.push(cb);
  if(_qrLoading)return; _qrLoading=true;
  const s=document.createElement('script');
  s.src='https://cdn.jsdelivr.net/npm/qrcode-generator@1.4.4/qrcode.js';
  s.onload=()=>{const cbs=_qrCbs;_qrCbs=[];cbs.forEach(f=>f());};
  s.onerror=()=>{_qrLoading=false;const cbs=_qrCbs;_qrCbs=[];cbs.forEach(f=>f(true));};
  document.head.appendChild(s);
}
function boletaShareURL(o){
  const data={emp:'Mercapp',when:o.when,n:o.n,dni:o.dni||'',tel:o.tel||'',mode:o.mode,a:o.a||'',sub:o.sub,igv:o.igv,delivery:o.delivery,total:o.total,greeting:o.greeting||'',
    items:(o.items||[]).map(i=>({n:i.name,k:i.kilos,p:i.price,t:i.total,v:i.vendor||'',m:i.market||''}))};
  return location.origin+location.pathname+'#b='+b64encUTF8(JSON.stringify(data));
}
function boletaQRDataURL(o,cb){
  ensureQR(err=>{
    if(err||!window.qrcode){cb('');return;}
    try{const qr=qrcode(0,'M');qr.addData(boletaShareURL(o));qr.make();cb(qr.createDataURL(4,8));}
    catch(e){cb('');}
  });
}
/* HTML completo de la boleta (sirve para descargar, previsualizar y la página del QR) */
function buildBoletaDoc(o,qr){
  const rows=(o.items||[]).map(i=>`<tr><td><b>${escapeHtml(i.name)}</b>${i.vendor?`<br><small>🏪 ${escapeHtml(storeShort(i.vendor))}</small>`:''}</td><td class="r">${i.kilos.toFixed(2)} kg</td><td class="r">${money(i.price)}</td><td class="r">${money(i.total)}</td></tr>`).join('');
  const fecha=new Date(o.when).toLocaleString('es-PE');
  const entrega=o.mode==='delivery' ? ('Delivery — '+escapeHtml(o.a||'')) : 'Recojo en tienda';
  const markets=[...new Set((o.items||[]).map(i=>i.market).filter(Boolean))].map(escapeHtml).join(' · ');
  const datos=[o.n?`Cliente: ${escapeHtml(o.n)}`:'', o.dni?`DNI: ${escapeHtml(o.dni)}`:'', o.tel?`Teléfono: ${escapeHtml(o.tel)}`:''].filter(Boolean).join(' · ');
  return `<!DOCTYPE html><html lang="es"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Boleta de venta · Mercapp</title>
<style>*{box-sizing:border-box}body{font-family:Arial,Helvetica,sans-serif;color:#1b211c;background:#f3f3f3;margin:0;padding:18px}
.boleta{max-width:520px;margin:0 auto;background:#fff;border:1px solid #e3e3e3;border-radius:14px;padding:22px clamp(16px,5vw,28px)}
.brand{text-align:center;border-bottom:2px solid #1f7a44;padding-bottom:12px;margin-bottom:14px}
.brand h1{margin:0;color:#1f7a44;font-size:clamp(24px,7vw,30px);letter-spacing:.5px}.brand small{color:#666}
.meta{font-size:13px;color:#444;margin:0 0 12px;line-height:1.55}
table{width:100%;border-collapse:collapse;font-size:14px;margin:10px 0}
th,td{padding:8px 6px;border-bottom:1px solid #eee;text-align:left;vertical-align:top}
th{color:#1f7a44;border-bottom:1px solid #1f7a44}.r{text-align:right;white-space:nowrap}
td small{color:#777}
.tot .row{display:flex;justify-content:space-between;padding:3px 0;font-size:14px}
.tot .total{font-size:18px;font-weight:bold;color:#1f7a44;border-top:1px solid #ccc;padding-top:8px;margin-top:6px}
.pay{margin-top:14px;font-size:14px}
.qr{text-align:center;margin-top:16px;border-top:1px dashed #ccc;padding-top:14px}
.qr img{width:140px;height:140px;image-rendering:pixelated}.qr small{display:block;color:#777;margin-top:6px;font-size:12px}
.thanks{margin-top:16px;text-align:center;font-style:italic;color:#1f7a44;font-weight:bold}
@media print{body{background:#fff;padding:0}.boleta{border:none}}</style></head><body>
<div class="boleta">
  <div class="brand"><h1>Mercapp</h1><small>Boleta de venta</small></div>
  <p class="meta">${fecha}<br>${datos}<br>Entrega: ${entrega}${markets?`<br>Lugar de compra: ${markets}`:''}</p>
  <table><thead><tr><th>Producto / Tienda</th><th class="r">Cant.</th><th class="r">P. kilo</th><th class="r">Importe</th></tr></thead><tbody>${rows}</tbody></table>
  <div class="tot">
    <div class="row"><span>Subtotal</span><span>${money(o.sub)}</span></div>
    <div class="row"><span>IGV (18%)</span><span>${money(o.igv)}</span></div>
    ${o.mode==='delivery'?`<div class="row"><span>Delivery</span><span>${money(o.delivery)}</span></div>`:''}
    <div class="row total"><span>Total</span><span>${money(o.total)}</span></div>
  </div>
  <p class="pay">Método de pago: <b>Yape</b></p>
  ${qr?`<div class="qr"><img src="${qr}" alt="Código QR de la boleta"><small>Escanea para ver esta boleta en línea</small></div>`:''}
  <p class="thanks">${escapeHtml(o.greeting||'')}</p>
</div></body></html>`;
}
function downloadBoleta(){
  const o=_lastReceipt; if(!o){toast('No hay boleta disponible');return;}
  boletaQRDataURL(o,qr=>{
    const blob=new Blob([buildBoletaDoc(o,qr)],{type:'text/html;charset=utf-8'});
    const url=URL.createObjectURL(blob);
    const a=document.createElement('a'); a.href=url; a.download='boleta-mercapp.html';
    document.body.appendChild(a); a.click(); a.remove();
    setTimeout(()=>URL.revokeObjectURL(url),2000);
    toast('Boleta descargada');
  });
}
/* Panel de pedidos del cliente + Ver boleta */
function openOrders(){
  closeModal();
  if(!requireAuth(openOrders)) return;
  const orders=(state.clientProfile&&state.clientProfile.orders)||[];
  const rows = orders.length ? orders.map((o,i)=>`
    <div class="orderrow">
      <div class="grow"><b>${new Date(o.when).toLocaleDateString('es-PE')}</b> · ${o.mode==='delivery'?'🛵 Delivery':'🏪 Recojo'}<br><small class="muted">${(o.items||[]).length} producto(s) · ${money(o.total)}</small></div>
      <button class="btn sm" onclick="openBoleta(${i})">Ver boleta</button>
    </div>`).join('') : '<div class="empty">Aún no tienes pedidos.</div>';
  modal(`<div class="modal" style="max-width:480px"><div class="modal-body">
    <h2 style="margin-top:0">Mis pedidos</h2>
    ${rows}
    <button class="btn ghost block" style="margin-top:14px" onclick="closeModal()">Cerrar</button>
  </div></div>`);
}
function openBoleta(i){
  const o=((state.clientProfile&&state.clientProfile.orders)||[])[i];
  if(!o){toast('Boleta no disponible');return;}
  _lastReceipt=o;
  boletaQRDataURL(o,qr=>{
    const doc=buildBoletaDoc(o,qr);
    modal(`<div class="modal" style="max-width:560px"><div class="modal-body">
      <h2 style="margin-top:0">Boleta de venta</h2>
      <iframe class="boletaframe" srcdoc="${escAttr(doc)}"></iframe>
      <button class="btn block" style="margin-top:12px" onclick="downloadBoleta()">📄 Descargar boleta</button>
      <button class="btn ghost block" style="margin-top:10px" onclick="openOrders()">← Mis pedidos</button>
    </div></div>`);
  });
}
/* Si la URL trae #b=, mostrar la boleta completa (destino del QR) */
function renderSharedBoletaIfAny(){
  const h=location.hash||'';
  if(h.indexOf('#b=')!==0) return false;
  try{
    const d=JSON.parse(b64decUTF8(h.slice(3)));
    const o={when:d.when,n:d.n,dni:d.dni,tel:d.tel,mode:d.mode,a:d.a,sub:d.sub,igv:d.igv,delivery:d.delivery,total:d.total,greeting:d.greeting,
      items:(d.items||[]).map(i=>({name:i.n,kilos:i.k,price:i.p,total:i.t,vendor:i.v,market:i.m}))};
    document.open(); document.write(buildBoletaDoc(o,'')); document.close();
    return true;
  }catch(e){ return false; }
}

